### Step 1 — Use useProviders

The useProviders hook gives you the list of providers, the currently selected provider/model, and a selectProvider function. It automatically fetches providers once connected.

```tsx title="ProviderPicker.tsx"
import { useProviders } from "@arlopass/react";

function ProviderPicker() {
  const {
    providers,         // list of available providers
    selectedProvider,  // { providerId, modelId } or null
    isLoading,
    error,
    selectProvider,    // call to switch provider + model
  } = useProviders();

  // We'll build the UI in the next steps
  return <div>Provider picker</div>;
}
```

### Step 2 — Wait for connection

Use useConnection to check whether the extension is connected before rendering the provider picker. The providers list is empty until connected.

```tsx title="ProviderPicker.tsx"
import { useConnection } from "@arlopass/react";

function ProviderPicker() {
  const { isConnected, isConnecting } = useConnection();
  const { providers, selectedProvider, selectProvider } = useProviders();

  if (isConnecting) return <p>Connecting to extension...</p>;
  if (!isConnected) return <p>Not connected. Is the extension installed?</p>;

  return (
    <div>
      <p>Connected! {providers.length} providers available.</p>
      {/* Dropdowns go here */}
    </div>
  );
}
```

### Step 3 — Render provider dropdown

Map the providers array to select options. When the user picks a provider, auto-select its first model.

```tsx title="ProviderPicker.tsx"
function ProviderPicker() {
  const { isConnected } = useConnection();
  const { providers, selectedProvider, selectProvider } = useProviders();

  if (!isConnected) return <p>Connecting...</p>;

  const currentProviderId = selectedProvider?.providerId ?? "";

  return (
    <div>
      <label htmlFor="provider-select">Provider</label>
      <select
        id="provider-select"
        value={currentProviderId}
        onChange={(e) => {
          const provider = providers.find((p) => p.id === e.target.value);
          if (provider && provider.models.length > 0) {
            selectProvider({
              providerId: provider.id,
              modelId: provider.models[0].id,
            });
          }
        }}
      >
        <option value="">Select a provider...</option>
        {providers.map((p) => (
          <option key={p.id} value={p.id}>
            {p.name}
          </option>
        ))}
      </select>
    </div>
  );
}
```

