### Step 5 — Handle selection

The selectProvider function takes a providerId and modelId. When switching providers, auto-select the first model.

```tsx title="ProviderPicker.tsx"
async function handleProviderChange(providerId: string) {
  const provider = providers.find((p) => p.id === providerId);
  if (!provider || provider.models.length === 0) return;

  // Select the first model from the new provider
  await selectProvider({
    providerId: provider.id,
    modelId: provider.models[0].id,
  });
}

async function handleModelChange(modelId: string) {
  if (!selectedProvider) return;
  await selectProvider({
    providerId: selectedProvider.providerId,
    modelId,
  });
}
